<script>
import {ref,reactive,computed} from 'vue'
export default {
  name:'HeaderVue',
  
  setup(){
    let isLogin=ref(window.localStorage.getItem('isLogin'))
    
    let cartItems=reactive(JSON.parse(localStorage.getItem('cart')))
    
    let isEmpty=computed(()=>{
      if(cartItems.items.length===0){
        return true
      }
      return false
    })
    

    return{
      isLogin,
      cartItems,
      isEmpty
    }
  },
  methods:{
    logout(){
      window.localStorage.removeItem('isLogin')
      this.$router.push('/').then(()=>{
        window.location.reload()
      })
    },
    goCart(){
      var cartBtn= document.getElementById('goCart')
      cartBtn.click()
      this.$router.push('/orderconfirm')
    },
    recountCart(){
      const newCartItems =JSON.parse(localStorage.getItem('cart'))
      this.cartItems.items=newCartItems.items
    },
    deleteItem(id){
      let cart=  JSON.parse(localStorage.getItem('cart'))
      for(var i=0;i<cart.items.length;i++){
        if(cart.items[i].id===id){
          cart.items.splice(i,1)
        }
      }
      localStorage.setItem('cart',JSON.stringify(cart))
      this.cartItems.items=cart.items
    }
    
  },
  mounted() {
    if(localStorage.getItem('cart')===null){
      localStorage.setItem('cart',JSON.stringify({items:[]}))
    }
  },
}
</script>

